class Solution {
public:
    int rearrangeCharacters(string s, string target) {
        unordered_map<char, int> targetFreq;
        for (char c : target) {
            targetFreq[c]++;
        }
        int count = 0;
        unordered_map<char, int> sFreq;
        for (char c : s) {
            sFreq[c]++;
        }
        for (auto it : targetFreq) {
            count = min(count, sFreq[it.first] / it.second);
        }
        return count;
    }
};
